DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextCurrency.pl", "contextPercent.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $decimal = random(0.16,0.20,0.01); Context("Currency")->flags->set(trimTrailingZeros => 1); $final = 90 + random(-30, 30, 0.05); $current = Currency($final); $solution = Round($final/(1 + $decimal), 2); $before = Currency($solution); Context("Percent"); $percent = Percent($decimal);
############################################################ # Body ############################################################
BEGIN_PGML The final bill at a restaurant one night was [`[$current]\text{,}`] including a [`[$percent]`] tip. What was the bill before the tip was added?
[_]{$before}{20}
END_PGML
